import React from 'react';
import './Portfolio.css';
import bibtexParse from 'bibtex-parse-js';

function Portfolio() {
  const bibtexEntries = `
    @inproceedings{islam2021allerhybrid,
      title={AllerHybrid: A Hybrid System to Predict the Allergen Using K-mer and Physicochemical Properties},
      author={Islam, Md Ruman and Kashem, Md Abul and Mia, Limon},
      booktitle={2021 5th International Conference on Electrical Engineering and Information Communication Technology (ICEEICT)},
      pages={1--6},
      year={2021},
      organization={IEEE}
    }

    @article{islam2024image,
      title={Image-based Deep Learning for Smart Digital Twins: a Review},
      author={Islam, Md Ruman and Subramaniam, Mahadevan and Huang, Pei-Chi},
      journal={arXiv preprint arXiv:2401.02523},
      year={2024}
    }

    @article{islam2024characterizing,
      title={Characterizing Encrypted Application Traffic through Cellular Radio Interface Protocol},
      author={Islam, Md Ruman and Anwar, Raja Hasnain and Mastorakis, Spyridon and Raza, Muhammad Taqi},
      journal={arXiv preprint arXiv:2407.07361},
      year={2024}
    }

    @article{zhang2024overcoming,
      title={Overcoming Autoware-Ubuntu Incompatibility in Autonomous Driving Systems-Equipped Vehicles: Lessons Learned},
      author={Zhang, Dada and Islam, Md Ruman and Huang, Pei-Chi and Ho, Chun-Hsing},
      journal={arXiv preprint arXiv:2410.06492},
      year={2024}
    }
  `;

  const publications = bibtexParse.entries(bibtexEntries);

  const formatAPA = (pub) => {
    const authors = pub.author
      .split(' and ')
      .map((name) => {
        const [lastName, firstName] = name.split(',').map((n) => n.trim());
        return `${lastName}, ${firstName.charAt(0)}.`;
      })
      .join(', ');

    const title = pub.title;
    const year = pub.year;

    let source = '';
    if (pub.journal) {
      source = `${pub.journal}.`;
    } else if (pub.booktitle) {
      source = `In ${pub.booktitle} (pp. ${pub.pages}). ${pub.organization}.`;
    }

    return `${authors} (${year}). ${title}. ${source}`;
  };

  return (
    <section id="portfolio" style={{ padding: '50px' }}>
      <h1>Publications</h1>
      <div className="publications">
        {publications.map((pub, index) => (
          <div key={index} className="publication">
            <p>{formatAPA(pub)}</p>
          </div>
        ))}
      </div>
    </section>
  );
}

export default Portfolio;
